884→func (pl *DynamicResources) Filter(ctx context.Context, cs fwk.CycleState, pod *v1.Pod, nodeInfo fwk.NodeInfo) *fwk.Status {
   885→	if !pl.enabled {
   886→		return nil
   887→	}
   888→	state, err := getStateData(cs)
   889→	if err != nil {
   890→		return statusError(klog.FromContext(ctx), err)
   891→	}
   892→	if state.claims.empty() {
   893→		return nil
   894→	}
   895→
   896→	logger := klog.FromContext(ctx)
   897→	node := nodeInfo.Node()
   898→	nodeExtendedResourceClaim, status := pl.filterExtendedResources(state, pod, nodeInfo, logger)
   899→	if status != nil {
   900→		return status
   901→	}
   902→	// The pod has no user claim, it may have extended resource claim that is satisfied by device plugin.
   903→	// Then there is nothing left to do for this plugin.
   904→	if nodeExtendedResourceClaim == nil && state.claims.noUserClaim() {
   905→		return nil
   906→	}
   907→
   908→	var unavailableClaims []int
   909→	for index, claim := range state.claims.all() {
   910→		logger.V(10).Info("filtering based on resource claims of the pod", "pod", klog.KObj(pod), "node", klog.KObj(node), "resourceclaim", klog.KObj(claim))
   911→
   912→		// This node selector only gets set if the claim is allocated.
   913→		if nodeSelector := state.informationsForClaim[index].availableOnNodes; nodeSelector != nil && !nodeSelector.Match(node) {
   914→			logger.V(5).Info("allocation's node selector does not match", "pod", klog.KObj(pod), "node", klog.KObj(node), "resourceclaim", klog.KObj(claim))
   915→			unavailableClaims = append(unavailableClaims, index)
   916→			continue
   917→		}
   918→
   919→		if claim.Status.Allocation == nil {
   920→			// The claim is not allocated yet, don't have to check
   921→			// anything else.
   922→			continue
   923→		}
   924→
   925→		// The claim is allocated, check whether it is ready for binding.
   926→		if pl.fts.EnableDRADeviceBindingConditions && pl.fts.EnableDRAResourceClaimDeviceStatus {
   927→			ready, err := pl.isClaimReadyForBinding(claim)
   928→			// If the claim is not ready yet (ready false, no error) and binding has timed out
   929→			// or binding has failed (err non-nil), then the scheduler should consider deallocating this
   930→			// claim in PostFilter to unblock trying other devices.
   931→			if err != nil || !ready && pl.isClaimTimeout(claim) {
   932→				unavailableClaims = append(unavailableClaims, index)
   933→			}
   934→		}
   935→	}
